document.addEventListener("DOMContentLoaded", function() {
  const container = document.getElementById('bookmarks-list');
  const bookmarks = JSON.parse(localStorage.getItem('user_bookmarks')) || [];

  if (bookmarks.length > 0) {
    // Limpa o texto padrão de vazio
    container.innerHTML = '';
    const ul = container.querySelector('ul');

    bookmarks.forEach((b, index) => {
      const li = document.createElement('li');
      li.style.cssText = 'padding: 15px; border-bottom: 1px solid #eee; display: flex; justify-content: space-between; align-items: center;';

      li.innerHTML = `

          ${b.title}

          Saved on: ${b.time}

        Remove
      `;
      ul.appendChild(li);
    });
  }
});

// Função rápida para permitir que o leitor limpe itens direto da lista
function removeBookmark(index) {
  let bookmarks = JSON.parse(localStorage.getItem('user_bookmarks')) || [];
  bookmarks.splice(index, 1);
  localStorage.setItem('user_bookmarks', JSON.stringify(bookmarks));
  window.location.reload(); // Recarrega a página para atualizar a lista
}


